    private boolean isIllegalType(Class<?> rawClass) {
        // Example blacklist, should be configurable
        String[] blacklistedClasses = {"com.sun.org.apache.xalan.internal.xsltc.trax.TemplatesImpl", "org.example.BlacklistedClass"};
        for (String className : blacklistedClasses) {
